arguments.new_str:
using Microsoft.ML;
using Microsoft.Extensions.ML;
using ChurnPredictor.Models;

var builder = WebApplication.CreateBuilder(args);

var mlContext = new MLContext(seed: 42);

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');

var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);

var pipeline = mlContext.Transforms.CustomMapping<CustomerData, ChurnLabel>(
        (input, output) => output.Label = input.Churned == "Yes",
        contractName: "ChurnMapping")
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.LbfgsLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

var model = pipeline.Fit(split.TrainSet);

var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

Console.WriteLine("=== Churn Prediction Model Metrics ===");
Console.WriteLine($"AUC:      {metrics.AreaUnderRocCurve:F4}");
Console.WriteLine($"F1 Score: {metrics.F1Score:F4}");
Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}");

var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn_model.zip");
mlContext.Model.Save(model, dataView.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath: modelPath);

var app = builder.Build();

app.MapGet("/", () => "Hello");

app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerData customer) =>
{
    var prediction = pool.Predict(customer);
    return Results.Ok(new
    {
        prediction.PredictedLabel,
        prediction.Probability,
        prediction.Score,
        WillChurn = prediction.PredictedLabel ? "Yes" : "No"
    });
});

app.Run();

public class ChurnLabel
{
    public bool Label { get; set; }
}

